 35→  'advanced',
 36→];
 37→
 38→function isSettingsTab(value: string): value is SettingsTab {
 39→  return SETTINGS_TABS.includes(value as SettingsTab);
 40→}
 41→
 42→interface GeneralSettings {
 43→  appearance: string;
 44→  windowPosition: string;
 45→  windowWidth: string;
 46→  showRecentApps: boolean;
 47→  showDock: boolean;
 48→  fontSize: string;
 49→}
 50→
 51→const SETTINGS_STORAGE_KEY = 'settings-general';
 52→const EXTENSIONS_STORAGE_KEY = 'settings-extensions';
 53→
 54→const DEFAULT_SETTINGS: GeneralSettings = {
 55→  appearance: 'dark',
 56→  windowPosition: 'top-third',
 57→  windowWidth: 'medium',
 58→  showRecentApps: true,
 59→  showDock: true,
 60→  fontSize: 'default',
 61→};
 62→
 63→function isGeneralSettings(value: unknown): value is GeneralSettings {
 64→  if (!isRecord(value)) return false;
 65→  return (
 66→    typeof value.appearance === 'string' &&
 67→    typeof value.windowWidth === 'string' &&
 68→    typeof value.showRecentApps === 'boolean' &&
 69→    typeof value.showDock === 'boolean' &&
 70→    typeof value.fontSize === 'string' &&
 71→    (value.windowPosition === undefined || typeof value.windowPosition === 'string')
 72→  );
 73→}
