601→export function SettingsView() {
602→  const nav = useNavigation();
603→  const { preference: themePreference, setTheme } = useTheme();
604→  const { setPositionPreference } = useWindow();
605→  const [query, setQuery] = useState('');
606→  const [activeTab, setActiveTab] = useState<SettingsTab>('general');
607→  const [actionsOpen, setActionsOpen] = useState(false);
608→  const [settings, setSettings] = useState<GeneralSettings>(() =>
609→    loadSettings(themePreference));
610→  const [extensions, setExtensions] =
611→    useState<ExtensionEntry[]>(loadExtensions);
612→  const { items: hudItems, show: showHUD } = useHUD();
613→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
614→
615→  const handleSettingsChange = useCallback(
616→    (newSettings: GeneralSettings) => {
617→      setSettings(newSettings);
618→      storageSet(SETTINGS_STORAGE_KEY, newSettings);
619→      if (
620→        newSettings.appearance === 'dark' ||
621→        newSettings.appearance === 'light' ||
622→        newSettings.appearance === 'system'
623→      ) {
624→        setTheme(newSettings.appearance);
625→      }
626→    },
627→    [setTheme],
628→  );
629→
630→  const handleQueryChange = useCallback((value: string) => {
631→    setQuery(value);
632→  }, []);
633→
634→  const handleTabChange = useCallback((value: string) => {
635→    if (isSettingsTab(value)) {
636→      setActiveTab(value);
637→      setQuery('');
638→    }
639→  }, []);
640→
641→  const handleToggleExtension = useCallback((id: string) => {
642→    setExtensions(prev => {
643→      const next = prev.map(ext =>
644→        ext.id === id
645→          ? {
646→              ...ext,
647→              enabled: !ext.enabled,
648→            }
649→          : ext);
650→      const states: Record<string, boolean> = {};
651→      for (const ext of next) {
652→        states[ext.id] = ext.enabled;
653→      }
654→      storageSet(EXTENSIONS_STORAGE_KEY, states);
655→      return next;
656→    });
657→  }, []);
658→
659→  const handleExport = useCallback(() => {
660→    showHUD({
661→      icon: <SuccessHUDIcon />,
662→      title: 'Settings Exported',
